// Secure random provider - wraps SecureRandom instead of scala.util.Random
object SecureRandomProvider {
  // Use SecureRandom instead of scala.util.Random for cryptographic security
  private val secureRandom: SecureRandom = new SecureRandom()

  private val alphanumericChars: Array[Char] =
    (('a' to 'z') ++ ('A' to 'Z') ++ ('0' to '9')).toArray

  def generateSecureToken(length: Int): String = {
    val bytes = new Array[Byte](length)
    secureRandom.nextBytes(bytes)
    Base64.getUrlEncoder.withoutPadding().encodeToString(bytes)
  }

  def generateSecureAlphanumeric(length: Int): String = {
    val sb = new StringBuilder(length)
    for (_ <- 0 until length) {
      val index = secureRandom.nextInt(alphanumericChars.length)
      sb.append(alphanumericChars(index))
    }
    sb.toString()
  }

  def generateSecureBytes(length: Int): Array[Byte] = {
    val bytes = new Array[Byte](length)
    secureRandom.nextBytes(bytes)
    bytes
  }
}

// Token encryption service
class TokenEncryptionService(masterKey: SecretKey) {
  private val GCM_TAG_LENGTH = 128
  private val GCM_IV_LENGTH = 12
  private val ALGORITHM = "AES/GCM/NoPadding"

  def encrypt(plainText: String): String = {
    val iv = SecureRandomProvider.generateSecureBytes(GCM_IV_LENGTH)
    val cipher = Cipher.getInstance(ALGORITHM)
    val parameterSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv)
    cipher.init(Cipher.ENCRYPT_MODE, masterKey, parameterSpec)

    val cipherText = cipher.doFinal(plainText.getBytes("UTF-8"))

    // Prepend IV to ciphertext
    val combined = new Array[Byte](iv.length + cipherText.length)
    System.arraycopy(iv, 0, combined, 0, iv.length)
    System.arraycopy(cipherText, 0, combined, iv.length, cipherText.length)

    Base64.getUrlEncoder.withoutPadding().encodeToString(combined)
  }

  def decrypt(encryptedText: String): Try[String] = Try {
    val combined = Base64.getUrlDecoder.decode(encryptedText)

    val iv = new Array[Byte](GCM_IV_LENGTH)
    val cipherText = new Array[Byte](combined.length - GCM_IV_LENGTH)
    System.arraycopy(combined, 0, iv, 0, GCM_IV_LENGTH)
    System.arraycopy(combined, GCM_IV_LENGTH, cipherText, 0, cipherText.length)

    val cipher = Cipher.getInstance(ALGORITHM)
    val parameterSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv)
    cipher.init(Cipher.DECRYPT_MODE, masterKey, parameterSpec)

    new String(cipher.doFinal(cipherText), "UTF-8")
  }
}

// Secure key management
object KeyManagement {
  def generateMasterKey(): SecretKey = {
    val keyGen = KeyGenerator.getInstance("AES")
    keyGen.init(256, new SecureRandom())
    keyGen.generateKey()
  }

  def deriveKeyFromBytes(keyBytes: Array[Byte]): SecretKey = {
    require(keyBytes.length == 32, "Key must be 256 bits (32 bytes)")
    new SecretKeySpec(keyBytes, "AES")
  }

  def exportKey(key: SecretKey): String = {
    Base64.getEncoder.encodeToString(key.getEncoded)
  }

  def importKey(encodedKey: String): SecretKey = {
    val keyBytes = Base64.getDecoder.decode(encodedKey)
    new SecretKeySpec(keyBytes, "AES")
  }
}

// Token store with thread-safe operations
class TokenStore {
  private val tokens: TrieMap[String, TokenMetadata] = TrieMap.empty
  private val userTokens: TrieMap[String, Set[String]] = TrieMap.empty

  def store(tokenHash: String, metadata: TokenMetadata): Unit = {
    tokens.put(tokenHash, metadata)
    userTokens.updateWith(metadata.userId) {
      case Some(existing) => Some(existing + tokenHash)
      case None => Some(Set(tokenHash))
    }
  }

  def retrieve(tokenHash: String): Option[TokenMetadata] = {
    tokens.get(tokenHash).flatMap { metadata =>
      if (metadata.isRevoked) None
      else if (Instant.now().isAfter(metadata.expiresAt)) {
        revoke(tokenHash)
        None
      } else Some(metadata)
    }
  }

  def revoke(tokenHash: String): Boolean = {
    tokens.get(tokenHash) match {
      case Some(metadata) =>
        tokens.put(tokenHash, metadata.copy(isRevoked = true))
        true
      case None => false
    }
  }

  def revokeAllForUser(userId: String): Int = {
    userTokens.get(userId) match {
      case Some(tokenHashes) =>
        tokenHashes.foreach(revoke)
        tokenHashes.size
      case None => 0
    }
  }

  def cleanupExpired(): Int = {
    val now = Instant.now()
    val expired = tokens.filter { case (_, metadata) =>
      now.isAfter(metadata.expiresAt) || metadata.isRevoked
    }
    expired.foreach { case (hash, metadata) =>
      tokens.remove(hash)
      userTokens.updateWith(metadata.userId) {
        case Some(existing) =>
          val updated = existing - hash
          if (updated.isEmpty) None else Some(updated)
        case None => None
      }
    }
    expired.size
  }

  def getActiveSessionCount(userId: String): Int = {
    userTokens.get(userId).map { tokenHashes =>
      tokenHashes.count(hash => tokens.get(hash).exists(m => !m.isRevoked && Instant.now().isBefore(m.expiresAt)))
    }.getOrElse(0)
  }
}

// Token hashing for secure storage
object TokenHasher {
  import java.security.MessageDigest

  def hash(token: String): String = {
    val digest = MessageDigest.getInstance("SHA-256")
    val hashBytes = digest.digest(token.getBytes("UTF-8"))
    hashBytes.map("%02x".format(_)).mkString
  }
}

// Rate limiter for token generation
class RateLimiter(maxRequests: Int, windowDuration: Duration) {
  private val requests: TrieMap[String, List[Instant]] = TrieMap.empty

  def isAllowed(identifier: String): Boolean = {
    val now = Instant.now()
    val windowStart = now.minus(windowDuration)

    val recentRequests = requests.getOrElse(identifier, List.empty)
      .filter(_.isAfter(windowStart))

    if (recentRequests.size < maxRequests) {
      requests.put(identifier, now :: recentRequests)
      true
    } else {
      false
    }
  }
}

// Configuration
case class TokenServiceConfig(
  sessionTokenLength: Int = 48,
  apiKeyLength: Int = 64,
  refreshTokenLength: Int = 64,
  sessionDuration: Duration = Duration.ofHours(24),
  apiKeyDuration: Duration = Duration.ofDays(365),
  refreshTokenDuration: Duration = Duration.ofDays(30),
  maxSessionsPerUser: Int = 5,
  rateLimitMaxRequests: Int = 10,
  rateLimitWindow: Duration = Duration.ofMinutes(1)
)

// Main token generation service
class TokenGenerationService(config: TokenServiceConfig = TokenServiceConfig()) {
  private val masterKey: SecretKey = KeyManagement.generateMasterKey()
  private val encryptionService = new TokenEncryptionService(masterKey)
  private val tokenStore = new TokenStore()
  private val rateLimiter = new RateLimiter(config.rateLimitMaxRequests, config.rateLimitWindow)

  def generateSessionToken(
    userId: String,
    ipAddress: Option[String] = None,
    userAgent: Option[String] = None
  ): Either[String, TokenResult] = {
    if (!rateLimiter.isAllowed(userId)) {
      return Left("Rate limit exceeded. Please try again later.")
    }

    if (tokenStore.getActiveSessionCount(userId) >= config.maxSessionsPerUser) {
      return Left(s"Maximum active sessions (${config.maxSessionsPerUser}) reached. Please revoke an existing session.")
    }

    val now = Instant.now()
    val tokenId = UUID.randomUUID().toString

    // Generate cryptographically secure token
    val rawToken = SecureRandomProvider.generateSecureToken(config.sessionTokenLength)

    // Create composite token with metadata prefix
    val compositeToken = s"sess_${rawToken}"

    // Encrypt the token for storage reference
    val encryptedToken = encryptionService.encrypt(compositeToken)

    val metadata = TokenMetadata(
      tokenId = tokenId,
      tokenType = SessionToken,
      userId = userId,
      createdAt = now,
      expiresAt = now.plus(config.sessionDuration),
      ipAddress = ipAddress,
      userAgent = userAgent
    )

    // Store hash of token (never store raw tokens)
    val tokenHash = TokenHasher.hash(compositeToken)
    tokenStore.store(tokenHash, metadata)

    Right(TokenResult(compositeToken, metadata))
  }

  def generateApiKey(
    userId: String,
    ipAddress: Option[String] = None
  ): Either[String, TokenResult] = {
    if (!rateLimiter.isAllowed(s"apikey_$userId")) {
      return Left("Rate limit exceeded for API key generation.")
    }

    val now = Instant.now()
    val tokenId = UUID.randomUUID().toString

    // Generate cryptographically secure API key
    val rawKey = SecureRandomProvider.generateSecureAlphanumeric(config.apiKeyLength)
    val compositeKey = s"ak_${rawKey}"

    val metadata = TokenMetadata(
      tokenId = tokenId,
      tokenType = ApiKey,
      userId = userId,
      createdAt = now,
      expiresAt = now.plus(config.apiKeyDuration),
      ipAddress = ipAddress
    )

    val tokenHash = TokenHasher.hash(compositeKey)
    tokenStore.store(tokenHash, metadata)

    Right(TokenResult(compositeKey, metadata))
  }

  def generateRefreshToken(
    userId: String,
    ipAddress: Option[String] = None
  ): Either[String, TokenResult] = {
    if (!rateLimiter.isAllowed(s"refresh_$userId")) {
      return Left("Rate limit exceeded for refresh token generation.")
    }

    val now = Instant.now()
    val tokenId = UUID.randomUUID().toString

    val rawToken = SecureRandomProvider.generateSecureToken(config.refreshTokenLength)
    val compositeToken = s"rt_${rawToken}"

    val metadata = TokenMetadata(
      tokenId = tokenId,
      tokenType = RefreshToken,
      userId = userId,
      createdAt = now,
      expiresAt = now.plus(config.refreshTokenDuration),
      ipAddress = ipAddress
    )

    val tokenHash = TokenHasher.hash(compositeToken)
    tokenStore.store(tokenHash, metadata)

    Right(TokenResult(compositeToken, metadata))
  }

  def validateToken(token: String): Option[TokenMetadata] = {
    val tokenHash = TokenHasher.hash(token)
    tokenStore.retrieve(tokenHash)
  }

  def revokeToken(token: String): Boolean = {
    val tokenHash = TokenHasher.hash(token)
    tokenStore.revoke(tokenHash)
  }

  def revokeAllUserSessions(userId: String): Int = {
    tokenStore.revokeAllForUser(userId)
  }

  def refreshSession(
    refreshToken: String,
    userId: String,
    ipAddress: Option[String] = None,
    userAgent: Option[String] = None
  ): Either[String, (TokenResult, TokenResult)] = {
    validateToken(refreshToken) match {
      case Some(metadata) if metadata.tokenType == RefreshToken && metadata.userId == userId =>
        // Revoke old refresh token (rotation)
        revokeToken(refreshToken)

        // Generate new session and refresh tokens
        val sessionResult = generateSessionToken(userId, ipAddress, userAgent)
        val newRefreshResult = generateRefreshToken(userId, ipAddress)

        (sessionResult, newRefreshResult) match {
          case (Right(session), Right(refresh)) => Right((session, refresh))
          case (Left(err), _) => Left(err)
          case (_, Left(err)) => Left(err)
        }

      case Some(_) => Left("Invalid token type for refresh operation.")
      case None => Left("Invalid or expired refresh token.")
    }
  }

  def cleanupExpiredTokens(): Int = {
    tokenStore.cleanupExpired()
  }

  def getActiveSessionCount(userId: String): Int = {
    tokenStore.getActiveSessionCount(userId)
  }
}

